import React, { useState, useEffect } from "react";
import { Link, Outlet, useNavigate, useLocation } from "react-router-dom";
import {
  Home,
  Users,
  List,
  BarChart2,
  DollarSign,
  LogOut,
  Menu,
  X,
} from "react-feather";

export default function AdminLayout() {
  const navigate = useNavigate();
  const location = useLocation();
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);
  const [isMobile, setIsMobile] = useState(window.innerWidth <= 768);

  // ✅ Detect mobile / desktop screen
  useEffect(() => {
    const handleResize = () => {
      const mobile = window.innerWidth <= 768;
      setIsMobile(mobile);
      if (!mobile) setIsSidebarOpen(true); // desktop -> sidebar open
    };
    window.addEventListener("resize", handleResize);
    handleResize();
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const logout = () => {
    localStorage.clear();
    navigate("/login", { replace: true });
  };

  // ✅ Auto close sidebar on link click (for mobile only)
  const handleNavClick = () => {
    if (isMobile) setIsSidebarOpen(false);
  };

  return (
    <div
      style={{
        display: "flex",
        minHeight: "100vh",
        backgroundColor: "#f6f9fc",
        overflowX: "hidden",
      }}
    >
      {/* Sidebar */}
      <aside
        style={{
          width: isSidebarOpen ? 240 : 0,
          background: "#13385a",
          color: "#fff",
          padding: isSidebarOpen ? "24px" : 0,
          transition: "all 0.3s ease-in-out",
          overflow: "hidden",
          position: isMobile ? "fixed" : "sticky",
          top: 0,
          left: isMobile ? (isSidebarOpen ? 0 : "-240px") : 0,
          height: "100vh",
          zIndex: 100,
        }}
      >
        {/* Header inside sidebar */}
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <h4 style={{ margin: 0, fontSize: "1.2rem" }}>Broker Admin</h4>
          {isMobile && (
            <button
              onClick={() => setIsSidebarOpen(false)}
              style={{
                background: "transparent",
                border: "none",
                color: "#fff",
                cursor: "pointer",
              }}
              className="close-btn"
            >
              <X size={24} />
            </button>
          )}
        </div>

        <ul style={{ listStyle: "none", marginTop: 30, padding: 0 }}>
          <li style={styles.navItem}>
            <Link
              to="/admin"
              style={{
                ...styles.link,
                background:
                  location.pathname === "/admin" ? "#0f2942" : "transparent",
              }}
              onClick={handleNavClick}
            >
              <Home size={18} style={styles.icon} /> Dashboard
            </Link>
          </li>
          <li style={styles.navItem}>
            <Link
              to="/admin/users"
              style={{
                ...styles.link,
                background:
                  location.pathname === "/admin/users" ? "#0f2942" : "transparent",
              }}
              onClick={handleNavClick}
            >
              <Users size={18} style={styles.icon} /> Users
            </Link>
          </li>
          <li style={styles.navItem}>
            <Link
              to="/admin/CategoryManager"
              style={{
                ...styles.link,
                background:
                  location.pathname === "/admin/CategoryManager"
                    ? "#0f2942"
                    : "transparent",
              }}
              onClick={handleNavClick}
            >
              <List size={18} style={styles.icon} /> Category List
            </Link>
          </li>
          <li style={styles.navItem}>
            <Link
              to="/admin/priceanalytics"
              style={{
                ...styles.link,
                background:
                  location.pathname === "/admin/priceanalytics"
                    ? "#0f2942"
                    : "transparent",
              }}
              onClick={handleNavClick}
            >
              <BarChart2 size={18} style={styles.icon} /> Analytics
            </Link>
          </li>
          <li style={styles.navItem}>
            <Link
              to="/admin/pricelist"
              style={{
                ...styles.link,
                background:
                  location.pathname === "/admin/pricelist"
                    ? "#0f2942"
                    : "transparent",
              }}
              onClick={handleNavClick}
            >
              <DollarSign size={18} style={styles.icon} /> Price List
            </Link>
          </li>
        </ul>

        <button
          onClick={logout}
          style={{
            background: "#e74c3c",
            border: "none",
            padding: "10px 14px",
            color: "#fff",
            borderRadius: 6,
            marginTop: 20,
            cursor: "pointer",
            width: "100%",
            fontWeight: 500,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: 6,
          }}
        >
          <LogOut size={18} /> Logout
        </button>
      </aside>

      {/* Main Content */}
      <main
        style={{
          flex: 1,
          marginLeft: isMobile ? 0 : isSidebarOpen ? 240 : 0,
          transition: "margin 0.3s ease-in-out",
          width: "100%",
        }}
      >
        {/* Top Bar */}
        <div
          style={{
            background: "#fff",
            padding: "12px 20px",
            boxShadow: "0 1px 4px rgba(0,0,0,0.1)",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            position: "sticky",
            top: 0,
            zIndex: 99,
          }}
        >
          <button
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
            style={{
              background: "transparent",
              border: "none",
              cursor: "pointer",
              color: "#13385a",
            }}
          >
            {isSidebarOpen ? <X size={26} /> : <Menu size={26} />}
          </button>
          <h3 style={{ margin: 0, color: "#13385a", fontWeight: 600 }}>
            Admin Dashboard
          </h3>
          <div></div>
        </div>

        <div style={{ padding: "24px" }}>
          <Outlet />
        </div>
      </main>

      {/* Responsive CSS */}
      <style>
        {`
          @media (max-width: 768px) {
            aside {
              position: fixed;
              top: 0;
              left: ${isSidebarOpen ? "0" : "-240px"};
              width: 240px;
              height: 100vh;
              transition: left 0.3s ease-in-out;
              z-index: 100;
            }

            main {
              margin-left: 0 !important;
              width: 100%;
            }

            .close-btn {
              display: inline-block !important;
            }
          }

          a:hover {
            background: #0b2947 !important;
          }
        `}
      </style>
    </div>
  );
}

const styles = {
  navItem: {
    padding: "10px 0",
  },
  link: {
    display: "flex",
    alignItems: "center",
    gap: 10,
    color: "#fff",
    textDecoration: "none",
    fontSize: 15,
    fontWeight: 500,
    padding: "6px 8px",
    borderRadius: "6px",
    transition: "background 0.2s",
  },
  icon: {
    minWidth: 20,
  },
};
